<template>
  <div class="pops" v-show="isShow" @click.self="showClick">
    <transition name="popsV" duration="0">
      <div class="popVals" v-show="isShow">
        <div class="navBar">
          <div class="left_bar" @click="cancel">取消</div>
          <div class="title">{{ title }}</div>
          <div class="right_bar">确定</div>
        </div>
        <slot name="slots"></slot>
        <van-rate v-model="starVals" allow-half void-icon="star" void-color="#eee" />
        <div class="contents">
          <van-image
            width="100"
            height="100"
            src="../assets/1.jpg"
          />
        </div>
        <slot></slot>
      </div>
    </transition>
  </div>
</template>

<script>
export default {
  props: {
    isShow: {
      typeof: Boolean,
      default: false,
    },
    title: {
      typeof: String,
      default: "",
    },
    value:{
       typeof: Number,
      default: 0,
    }
  },
  data() {
    return {
      starVals:this.value
    };
  },
  methods: {
    showClick() {
      this.$emit("showClick");
    },
    cancel() {
      this.$emit("showClick");
    },
  },
};
</script>

<style lang="less">
.pops {
  position: fixed;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  background: rgba(0, 0, 0, 0.4);
  z-index: 999;
  overflow: hidden;
  .popVals {
    width: 100%;
    height: 50%;
    background-color: #fff;
    position: absolute;
    bottom: 0;
    transition: all 0.5s linear;
  }
  .navBar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.4rem;
    color: rgb(33, 22, 187);
    box-shadow: 0 0 10px rgba(102, 87, 87, 0.4);
    font-size: 15px;
    .title {
      color: #000;
      font-weight: bold;
      font-size: 20px;
    }
  }
}
.popsV-enter,
.popsV-leave-to {
  opacity: 0;
}
.popsV-enter-active {
  transform: translateY(100%);
}
.popsV-leave-active {
  transform: translateY(0%);
}
</style>