// 防抖函数
const debounce = function (fn, tim) {
    let timer = null;
    return function () {
        let that = this;
        let arg = arguments;
         if(timer){
             clearTimeout(timer);
         }
        timer = setTimeout(function () {
            fn.apply(that, arg)
        }, tim)
    }

}
export default {
    debounce
}